import okhttp3.OkHttpClient
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import retrofit2.http.GET
import retrofit2.Response
import retrofit2.Call

// Define API Interface
interface ApiService {
    @GET("users")
    suspend fun fetchUserProfiles(): Response<List<UserProfile>>
}

// User profile data class
data class UserProfile(
    val id: Int,
    val name: String,
    val email: String
)

// Networking Module
object NetworkingModule {

    private const val BASE_URL_DEV = "https://api.dev.example.com/"
    private const val BASE_URL_STAGING = "https://api.staging.example.com/"
    private const val BASE_URL_PRODUCTION = "https://api.example.com/"

    private var retrofit: Retrofit? = null

    fun getRetrofit(environment: String, authToken: String): Retrofit {
        if (retrofit == null) {
            val logging = HttpLoggingInterceptor().apply {
                level = HttpLoggingInterceptor.Level.BODY
            }

            val client = OkHttpClient.Builder()
                .addInterceptor(logging)
                .addInterceptor { chain ->
                    val original = chain.request()
                    val requestBuilder = original.newBuilder()
                        .header("Authorization", "Bearer $authToken")
                    val request = requestBuilder.build()
                    chain.proceed(request)
                }
                .build()

            val baseUrl = when (environment) {
                "dev" -> BASE_URL_DEV
                "staging" -> BASE_URL_STAGING
                "production" -> BASE_URL_PRODUCTION
                else -> BASE_URL_PRODUCTION
            }

            retrofit = Retrofit.Builder()
                .baseUrl(baseUrl)
                .client(client)
                .addConverterFactory(GsonConverterFactory.create())
                .build()
        }
        return retrofit!!
    }

    fun apiService(environment: String, authToken: String): ApiService {
        return getRetrofit(environment, authToken).create(ApiService::class.java)
    }
}